import{c as s,Q as t,j as n,m as o}from"./chunks/framework.CBiVa4O3.js";const h=JSON.parse('{"title":"ACID 在分布式下的崩塌","description":"","frontmatter":{},"headers":[],"relativePath":"../distributedLearning/20-ACID在分布式下的崩塌.md","filePath":"../distributedLearning/20-ACID在分布式下的崩塌.md","lastUpdated":1778496697000}'),e={name:"../distributedLearning/20-ACID在分布式下的崩塌.md"};function i(r,a,l,p,d,c){return t(),n("div",null,[...a[0]||(a[0]=[o(`<h1 id="acid-在分布式下的崩塌" tabindex="-1">ACID 在分布式下的崩塌 <a class="header-anchor" href="#acid-在分布式下的崩塌" aria-label="Permalink to &quot;ACID 在分布式下的崩塌&quot;">​</a></h1><p>19 篇结尾说:<strong>强一致 → 共识,最终一致 → CRDT,中间地带 → 因果一致</strong>。这一篇换个视角:从「事务」这个所有后端工程师吃了十年的概念入手,看看<strong>单机引以为豪的 ACID,跨机后是怎么一个字母一个字母被打破的</strong>。这一篇是第五层的&quot;开场白&quot;——它解释了为什么后面 21-24 篇要讲那一堆方案:<strong>2PC / Saga / TCC / Percolator / Spanner 全是在补 ACID 的破口</strong>,每个方案补哪个字母、付什么代价,看完这篇你就有了底图。</p><blockquote><p>一句话先记住:<strong>ACID 在单机靠&quot;一把锁 + 一个 WAL + 一次 fsync&quot;撑住,跨机后 A 要靠 2PC、C 要靠全局约束(几乎做不到)、I 要靠串行化(代价巨大)、D 要靠多数派持久(单 fsync 不够)</strong>。<strong>要 ACID,就得 2PC + 共识,慢且脆;要可用,就得削弱某字母,降级成 BASE / Saga / 最终一致</strong>。<strong>Spanner 是当代最接近&quot;分布式 ACID&quot;的怪物——靠原子钟硬把外部一致性买回来</strong>,可大多数公司没这条件,只能在 ACID 和可用性之间反复横跳。</p></blockquote><hr><h2 id="一、单机-acid-你以为是天经地义-其实是一台精密机器" tabindex="-1">一、单机 ACID:你以为是天经地义,其实是一台精密机器 <a class="header-anchor" href="#一、单机-acid-你以为是天经地义-其实是一台精密机器" aria-label="Permalink to &quot;一、单机 ACID:你以为是天经地义,其实是一台精密机器&quot;">​</a></h2><p>先回顾单机 ACID 怎么获得——<strong>只有理解了单机怎么搞,才能理解分布式怎么破</strong>。</p><h3 id="_1-1-a-atomicity-原子性" tabindex="-1">1.1 A(Atomicity,原子性) <a class="header-anchor" href="#_1-1-a-atomicity-原子性" aria-label="Permalink to &quot;1.1 A(Atomicity,原子性)&quot;">​</a></h3><p><strong>全做或全不做,不能做一半</strong>。</p><p>实现:<strong>WAL(Write-Ahead Log,预写日志)+ Undo / Redo</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>执行事务 T:</span></span>
<span class="line"><span>  1. 写 WAL:T-BEGIN</span></span>
<span class="line"><span>  2. 写 WAL:T 修改了页 P,旧值 V1,新值 V2</span></span>
<span class="line"><span>  3. 在内存 buffer 中改页</span></span>
<span class="line"><span>  4. 写 WAL:T-COMMIT</span></span>
<span class="line"><span>  5. (异步)刷脏页到磁盘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>崩溃恢复:扫 WAL</span></span>
<span class="line"><span>  - 已 COMMIT 的:redo</span></span>
<span class="line"><span>  - 未 COMMIT 的:undo</span></span></code></pre></div><p><strong>A 的关键是 WAL 在 commit 前刷到磁盘</strong>——只要 WAL 上有 COMMIT 记录,事务就是 commit 了;否则就是没 commit,undo 掉。</p><h3 id="_1-2-c-consistency-一致性" tabindex="-1">1.2 C(Consistency,一致性) <a class="header-anchor" href="#_1-2-c-consistency-一致性" aria-label="Permalink to &quot;1.2 C(Consistency,一致性)&quot;">​</a></h3><p><strong>数据库永远满足业务约束</strong>(主键、外键、CHECK、唯一索引)。</p><p>实现:<strong>约束检查 + A I D 三个保证下自然导出</strong>。</p><p>C 是&quot;数据库视角的一致性&quot;,<strong>和 CAP 的 C(线性一致)是两个东西</strong>——这是分布式领域最容易混淆的两个概念,后面会专门强调。</p><h3 id="_1-3-i-isolation-隔离性" tabindex="-1">1.3 I(Isolation,隔离性) <a class="header-anchor" href="#_1-3-i-isolation-隔离性" aria-label="Permalink to &quot;1.3 I(Isolation,隔离性)&quot;">​</a></h3><p><strong>并发事务互不干扰</strong>。</p><p>实现:<strong>锁 + MVCC</strong>。</p><ul><li>串行化(Serializable):两阶段锁(2PL)</li><li>可重复读(RR):MVCC + 行锁</li><li>读已提交(RC):MVCC + 短锁</li><li>读未提交(RU):几乎不锁,脏读</li></ul><p><strong>隔离级别越强,并发度越低</strong>——这是单机内部就有的取舍,分布式只是放大了它。</p><h3 id="_1-4-d-durability-持久性" tabindex="-1">1.4 D(Durability,持久性) <a class="header-anchor" href="#_1-4-d-durability-持久性" aria-label="Permalink to &quot;1.4 D(Durability,持久性)&quot;">​</a></h3><p><strong>commit 后即使断电也不丢</strong>。</p><p>实现:<strong>fsync(WAL 写到物理磁盘 / SSD 的非易失介质)</strong>。</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 简化的 commit</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">write_wal_record(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;T-COMMIT&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fsync(wal_fd)   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ← 这一行是 D 的命根子</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> success</span></span></code></pre></div><p><strong>没有 fsync,所谓 commit 只是 page cache 里的字节</strong>——掉电就没。</p><h3 id="_1-5-单机-acid-的物理基础" tabindex="-1">1.5 单机 ACID 的物理基础 <a class="header-anchor" href="#_1-5-单机-acid-的物理基础" aria-label="Permalink to &quot;1.5 单机 ACID 的物理基础&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────┐</span></span>
<span class="line"><span>│         单机 ACID 全靠              │</span></span>
<span class="line"><span>├─────────────────────────────────────┤</span></span>
<span class="line"><span>│  1. 一把 mutex(进程内全序保证)     │</span></span>
<span class="line"><span>│  2. 一个 WAL(顺序持久化)           │</span></span>
<span class="line"><span>│  3. 一次 fsync(物理介质持久化)     │</span></span>
<span class="line"><span>│  4. 一个内存页缓存(buffer pool)   │</span></span>
<span class="line"><span>└─────────────────────────────────────┘</span></span></code></pre></div><p><strong>核心假设</strong>:<strong>有一个&quot;共享内存 + 共享磁盘&quot;的物理边界</strong>——所有线程在一个进程里,所有 IO 落到同一块磁盘。<strong>这个假设一跨机就死</strong>。</p><hr><h2 id="二、跨机后-a-怎么破" tabindex="-1">二、跨机后,A 怎么破 <a class="header-anchor" href="#二、跨机后-a-怎么破" aria-label="Permalink to &quot;二、跨机后,A 怎么破&quot;">​</a></h2><p>事务跨多台机器执行:转账,A 库扣 100,B 库加 100。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>T:</span></span>
<span class="line"><span>  begin</span></span>
<span class="line"><span>  A 库:UPDATE accounts SET balance -= 100 WHERE id = &#39;alice&#39;</span></span>
<span class="line"><span>  B 库:UPDATE accounts SET balance += 100 WHERE id = &#39;bob&#39;</span></span>
<span class="line"><span>  commit</span></span></code></pre></div><p><strong>问题</strong>:<code>commit</code> 怎么&quot;两边一起 commit&quot;?</p><ul><li>A 库 commit 成功,B 库 commit 失败 → <strong>钱凭空消失</strong></li><li>A 库 commit 失败,B 库 commit 成功 → <strong>钱凭空多出</strong></li><li>A 库 commit 成功,B 库 网络超时 → <strong>不知道 B 库 commit 没有</strong></li></ul><p><strong>单机不会有这问题</strong>——单机的 commit 是一次 WAL 刷盘,要么成要么不成,<strong>没有&quot;一半&quot;状态</strong>。分布式有,因为两台机器各自有自己的 WAL,<strong>没有&quot;一次刷&quot;的物理动作</strong>。</p><blockquote><p>A 破的根源:<strong>单机靠&quot;一次原子刷盘&quot;得到 A,分布式没有这个原子动作</strong>——必须发明一个跨机的&quot;伪原子动作&quot;。这就是 <strong>2PC</strong>(21 篇)的来源。</p></blockquote><p>但 2PC 自身有命门:</p><ul><li>协调者挂了,参与者卡死(blocking forever)</li><li>同步阻塞,延迟 = max(所有参与者)</li><li>失败恢复极痛苦</li></ul><p>所以工程上经常<strong>放弃强 A</strong>,改用 <strong>Saga / TCC</strong>(22 篇)——业务级补偿:第二步失败就回滚第一步。<strong>这不是真 A,是&quot;业务层 A&quot;</strong>——中间状态业务可见,但最终结果&quot;看起来像原子&quot;。</p><hr><h2 id="三、跨机后-c-怎么破" tabindex="-1">三、跨机后,C 怎么破 <a class="header-anchor" href="#三、跨机后-c-怎么破" aria-label="Permalink to &quot;三、跨机后,C 怎么破&quot;">​</a></h2><p><strong>全局约束跨节点几乎做不到</strong>。</p><h3 id="_3-1-全局唯一" tabindex="-1">3.1 全局唯一 <a class="header-anchor" href="#_3-1-全局唯一" aria-label="Permalink to &quot;3.1 全局唯一&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>分库分表:用户表按 user_id 分 16 片</span></span>
<span class="line"><span>约束:邮箱必须全局唯一</span></span>
<span class="line"><span></span></span>
<span class="line"><span>T1 在分片 3 插入:email = &#39;a@x.com&#39;</span></span>
<span class="line"><span>T2 在分片 7 同时插入:email = &#39;a@x.com&#39;</span></span>
<span class="line"><span>两个分片各自看本地,都允许 → 全局重复</span></span></code></pre></div><p><strong>单机的 UNIQUE 索引救不了你</strong>——它只保证单库唯一,跨库要<strong>外加协调</strong>。</p><p><strong>怎么救</strong>:</p><ol><li><strong>路由层把同一约束的数据路由到同一节点</strong>——邮箱按 hash 分片,但这样查询不灵活</li><li><strong>全局唯一服务</strong>(Redis SETNX、ZooKeeper 创建节点)——加一跳网络 + 强一致服务</li><li><strong>乐观:先写后检测,冲突时回滚</strong>——业务复杂</li></ol><h3 id="_3-2-外键约束" tabindex="-1">3.2 外键约束 <a class="header-anchor" href="#_3-2-外键约束" aria-label="Permalink to &quot;3.2 外键约束&quot;">​</a></h3><p>跨库外键 MySQL 直接不支持。<strong>业务层自己保证</strong>——但业务层写错了,数据库不会救你。</p><h3 id="_3-3-业务级聚合约束" tabindex="-1">3.3 业务级聚合约束 <a class="header-anchor" href="#_3-3-业务级聚合约束" aria-label="Permalink to &quot;3.3 业务级聚合约束&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;用户总订单数 ≤ 100&quot;</span></span>
<span class="line"><span>订单分散在多个分片,无法在单事务里查完所有分片再判断</span></span></code></pre></div><p><strong>DDD 的&quot;聚合根&quot;概念就是为了这个</strong>——把一致性边界限制在一个聚合内,跨聚合走最终一致。</p><blockquote><p><strong>C 破的根源:全局约束需要&quot;全局视图&quot;,但分布式系统连&quot;全局视图&quot;都难得到</strong>(看 18 篇因果一致那里)。<strong>工程妥协:把强约束限制在一个 shard / 聚合根内,跨边界走最终一致 + 对账兜底</strong>。</p></blockquote><h3 id="_3-4-注意-acid-的-c-cap-的-c" tabindex="-1">3.4 注意:ACID 的 C ≠ CAP 的 C <a class="header-anchor" href="#_3-4-注意-acid-的-c-cap-的-c" aria-label="Permalink to &quot;3.4 注意:ACID 的 C ≠ CAP 的 C&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th>ACID 的 C</th><th>CAP 的 C</th></tr></thead><tbody><tr><td>含义</td><td>业务约束不被破坏(外键 / 唯一 / CHECK)</td><td>多副本读写看到同一份数据(线性一致)</td></tr><tr><td>范围</td><td>单事务内</td><td>全集群所有节点</td></tr><tr><td>保证者</td><td>数据库引擎 + 应用</td><td>共识算法(Raft / Paxos)</td></tr></tbody></table><p><strong>两个 C 完全不同</strong>——分布式领域的术语污染让无数人混淆。</p><hr><h2 id="四、跨机后-i-怎么破" tabindex="-1">四、跨机后,I 怎么破 <a class="header-anchor" href="#四、跨机后-i-怎么破" aria-label="Permalink to &quot;四、跨机后,I 怎么破&quot;">​</a></h2><p><strong>串行化级别(SERIALIZABLE)代价巨大</strong>。</p><h3 id="_4-1-单机串行化怎么做" tabindex="-1">4.1 单机串行化怎么做 <a class="header-anchor" href="#_4-1-单机串行化怎么做" aria-label="Permalink to &quot;4.1 单机串行化怎么做&quot;">​</a></h3><p>最朴素:<strong>全局表锁,事务排队</strong>。</p><p>实用做法:<strong>2PL(两阶段锁)+ 死锁检测</strong> 或 <strong>SSI(Serializable Snapshot Isolation)+ 冲突检测</strong>。</p><p>无论哪种,<strong>所有锁信息都在一个进程内</strong>——锁表查询 O(1),死锁检测扫一个图。</p><h3 id="_4-2-跨机串行化的痛" tabindex="-1">4.2 跨机串行化的痛 <a class="header-anchor" href="#_4-2-跨机串行化的痛" aria-label="Permalink to &quot;4.2 跨机串行化的痛&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>事务 T1 在节点 A 操作行 r1,节点 B 操作行 r2</span></span>
<span class="line"><span>事务 T2 在节点 A 操作行 r2,节点 B 操作行 r1</span></span>
<span class="line"><span></span></span>
<span class="line"><span>死锁!但锁信息分散在两个节点,谁来检测?</span></span></code></pre></div><p>工程方案:</p><ol><li><strong>全局锁服务</strong>(分布式 lock manager)——加一跳,延迟翻倍</li><li><strong>2PC + 严格 2PL</strong>——commit 慢,死锁仍要检测</li><li><strong>OCC + 全局时间戳排序</strong>(Percolator / Spanner 路线)——23/24 篇详细讲</li></ol><h3 id="_4-3-实际上大多数分布式数据库的-最高-是-si" tabindex="-1">4.3 实际上大多数分布式数据库的&quot;最高&quot;是 SI <a class="header-anchor" href="#_4-3-实际上大多数分布式数据库的-最高-是-si" aria-label="Permalink to &quot;4.3 实际上大多数分布式数据库的&quot;最高&quot;是 SI&quot;">​</a></h3><ul><li>MySQL 单机:最高 SERIALIZABLE</li><li>TiDB / CockroachDB:<strong>默认 SI(快照隔离)</strong>,可选 SSI</li><li>Spanner:<strong>外部一致性 = 线性化 + SS2PL</strong>(代价是 TrueTime + 等待区间)</li><li>MongoDB / Cassandra:连 SI 都不到,<strong>应用层管隔离</strong></li></ul><p><strong>为什么不普及 Serializable?</strong>——分布式 SS2PL 的延迟和死锁代价,<strong>绝大多数业务接受不了</strong>。SI 已经能挡掉 95% 的并发问题,<strong>剩下 5% 业务自己加 SELECT FOR UPDATE 或乐观锁</strong>。</p><blockquote><p>I 破的根源:<strong>跨节点的锁管理 / 冲突检测,代价远大于单机</strong>。工程妥协:<strong>用 SI 代替 SERIALIZABLE,把&quot;幻读&quot;等小漏洞交给应用</strong>。</p></blockquote><hr><h2 id="五、跨机后-d-怎么破" tabindex="-1">五、跨机后,D 怎么破 <a class="header-anchor" href="#五、跨机后-d-怎么破" aria-label="Permalink to &quot;五、跨机后,D 怎么破&quot;">​</a></h2><p>D 看起来最简单(刷盘就行),<strong>其实最容易踩雷</strong>。</p><h3 id="_5-1-单-fsync-不够" tabindex="-1">5.1 单 fsync 不够 <a class="header-anchor" href="#_5-1-单-fsync-不够" aria-label="Permalink to &quot;5.1 单 fsync 不够&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>单机:write_wal + fsync → 数据持久</span></span>
<span class="line"><span></span></span>
<span class="line"><span>分布式:在 leader 上 fsync 了 → 数据是不是持久?</span></span>
<span class="line"><span></span></span>
<span class="line"><span>NO!</span></span>
<span class="line"><span>1. 这台 leader 接着挂了,磁盘坏了 → 数据没了</span></span>
<span class="line"><span>2. 这台 leader 接着挂了,SSD 还在 → 但被踢出集群,选了新 leader → 新 leader 没这个事务 → 实际上&quot;丢&quot;了</span></span></code></pre></div><p><strong>真正的分布式 D 要求</strong>:<strong>事务已被多数派持久化</strong>(majority durable),<strong>才能算 commit</strong>。</p><h3 id="_5-2-各种半同步-同步复制的真相" tabindex="-1">5.2 各种半同步 / 同步复制的真相 <a class="header-anchor" href="#_5-2-各种半同步-同步复制的真相" aria-label="Permalink to &quot;5.2 各种半同步 / 同步复制的真相&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模式</th><th>写入路径</th><th>何时返回 commit</th><th>D 保证</th></tr></thead><tbody><tr><td>MySQL 异步</td><td>主写 WAL + fsync → 返回</td><td>主 fsync 完</td><td>主挂可能丢</td></tr><tr><td>MySQL 半同步</td><td>主写 + 至少 1 个从收到 binlog → 返回</td><td>主 fsync + 1 个从内存收到</td><td>从挂可能丢(从没 fsync)</td></tr><tr><td>MySQL Loseless</td><td>主写 + 至少 1 个从 fsync</td><td>主 + 1 从都 fsync</td><td>主和这从同时挂才丢</td></tr><tr><td>PG 同步复制</td><td>主写 + N 个从 fsync(可配)</td><td>N 从都 fsync</td><td>多数派持久</td></tr><tr><td>Raft / Paxos</td><td>多数派持久后 leader 返回</td><td>majority fsync</td><td>多数派持久</td></tr></tbody></table><blockquote><p><strong>&quot;我 commit 返回了&quot;≠&quot;数据安全&quot;</strong>——必须问&quot;几台机器持久了&quot;。<strong>没有多数派持久化的 commit,都是单点 D</strong>——单点挂就完。</p></blockquote><h3 id="_5-3-真实事故-mysql-异步复制-自动-failover" tabindex="-1">5.3 真实事故:MySQL &quot;异步复制 + 自动 failover&quot; <a class="header-anchor" href="#_5-3-真实事故-mysql-异步复制-自动-failover" aria-label="Permalink to &quot;5.3 真实事故:MySQL &quot;异步复制 + 自动 failover&quot;&quot;">​</a></h3><p>经典翻车场景:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 主库写入 commit 返回成功</span></span>
<span class="line"><span>2. binlog 还没传给从库</span></span>
<span class="line"><span>3. 主库挂了 → 自动 failover,从库提升为主</span></span>
<span class="line"><span>4. 客户端读不到刚才那笔 → 用户傻眼</span></span></code></pre></div><p><strong>这不是 MySQL bug,这是异步复制的本质</strong> ——D 只在主库的磁盘上,没多数派持久。<strong>金融场景必须半同步 + 多数派</strong>,<strong>或者用 TiDB / CockroachDB / Spanner 这种原生多数派持久的系统</strong>。</p><blockquote><p>D 破的根源:<strong>单机 D = 单磁盘 fsync,分布式 D = 多数派持久</strong>——<strong>两者完全不同,不能混用</strong>。</p></blockquote><hr><h2 id="六、根本矛盾-acid-vs-可用性" tabindex="-1">六、根本矛盾:ACID vs 可用性 <a class="header-anchor" href="#六、根本矛盾-acid-vs-可用性" aria-label="Permalink to &quot;六、根本矛盾:ACID vs 可用性&quot;">​</a></h2><p>回到 04 篇 CAP:<strong>强一致(ACID)和可用性是天然冲突的</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ACID 要求事务跨节点协调 → 任一节点不可达,事务失败 → 可用性下降</span></span>
<span class="line"><span>可用性要求任何分区下都能服务 → 不等其他节点 → 不一致</span></span>
<span class="line"><span></span></span>
<span class="line"><span>要 ACID  → 2PC + 共识 → 慢、且脆(协调者挂、参与者挂、网络抖)</span></span>
<span class="line"><span>要可用  → 削弱某字母 → BASE / Saga / 最终一致</span></span></code></pre></div><h3 id="_6-1-两条工程路线" tabindex="-1">6.1 两条工程路线 <a class="header-anchor" href="#_6-1-两条工程路线" aria-label="Permalink to &quot;6.1 两条工程路线&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>路线 1:强 ACID(NewSQL)</span></span>
<span class="line"><span>└─ Spanner / TiDB / CockroachDB / OceanBase</span></span>
<span class="line"><span>   - 2PC + Paxos/Raft + 全局时钟</span></span>
<span class="line"><span>   - 牺牲少量可用性(CP)、运维复杂、延迟高</span></span>
<span class="line"><span>   - 适合金融账户 / 强一致核心库</span></span>
<span class="line"><span></span></span>
<span class="line"><span>路线 2:BASE(互联网架构主流)</span></span>
<span class="line"><span>└─ MySQL 分库 + 应用层补偿 + 消息事务表</span></span>
<span class="line"><span>   - Saga(长事务) / TCC(预占 + 确认 / 取消)</span></span>
<span class="line"><span>   - 业务级 A、最终一致</span></span>
<span class="line"><span>   - 适合电商订单 / 社交 / 内容</span></span></code></pre></div><p><strong>95% 的国内互联网公司用路线 2</strong>——理由是路线 1 运维成本高、改造历史系统贵。但金融核心、计费、对账,<strong>该上 ACID 还是要上</strong>。</p><h3 id="_6-2-acid-vs-base-vs-newsql-对比" tabindex="-1">6.2 ACID vs BASE vs NewSQL 对比 <a class="header-anchor" href="#_6-2-acid-vs-base-vs-newsql-对比" aria-label="Permalink to &quot;6.2 ACID vs BASE vs NewSQL 对比&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>单机 ACID</th><th>BASE(应用补偿)</th><th>NewSQL</th></tr></thead><tbody><tr><td>一致性</td><td>强</td><td>最终</td><td>强(SI / 线性)</td></tr><tr><td>可用性</td><td>低(单点)</td><td>高</td><td>中(多数派可用)</td></tr><tr><td>延迟</td><td>低</td><td>低(本地操作)</td><td>中(跨节点 RTT)</td></tr><tr><td>复杂度</td><td>低</td><td>高(写补偿、对账)</td><td>中(数据库自己处理)</td></tr><tr><td>运维</td><td>低</td><td>中</td><td>高</td></tr><tr><td>适合</td><td>单库小业务</td><td>互联网通用</td><td>金融 / 强一致核心</td></tr></tbody></table><hr><h2 id="七、spanner-tidb-分布式-acid-是怎么硬买回来的" tabindex="-1">七、Spanner / TiDB:&quot;分布式 ACID&quot;是怎么硬买回来的 <a class="header-anchor" href="#七、spanner-tidb-分布式-acid-是怎么硬买回来的" aria-label="Permalink to &quot;七、Spanner / TiDB:&quot;分布式 ACID&quot;是怎么硬买回来的&quot;">​</a></h2><p>Spanner 2012 论文核心一句话:<strong>&quot;我们提供外部一致性,代价是 GPS + 原子钟&quot;</strong>。</p><h3 id="_7-1-spanner-怎么做到-acid" tabindex="-1">7.1 Spanner 怎么做到 ACID <a class="header-anchor" href="#_7-1-spanner-怎么做到-acid" aria-label="Permalink to &quot;7.1 Spanner 怎么做到 ACID&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>- A:2PC(跨 Paxos group)</span></span>
<span class="line"><span>- C:数据库约束 + 串行化</span></span>
<span class="line"><span>- I:SS2PL(严格两阶段锁)+ MVCC,**TrueTime 提供线性化时间戳**</span></span>
<span class="line"><span>- D:每个 Paxos group 多数派持久</span></span></code></pre></div><p><strong>关键创新是 TrueTime API</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>TT.now() → TTinterval { earliest, latest }   // 注意是区间不是点</span></span>
<span class="line"><span>TT.after(t) → bool                            // t 之前是否一定过去了</span></span>
<span class="line"><span>TT.before(t) → bool                           // t 之后是否一定还没到</span></span></code></pre></div><p>事务 commit 时<strong>等待&quot;绝对最近的时间戳&quot;过去</strong>(commit-wait),保证所有副本看到的时间戳全序。</p><p>代价:</p><ul><li>每个数据中心装原子钟 + GPS(物理硬件)</li><li>每个 commit 多等 7ms(commit-wait)</li><li>5 个 9 可用性,但仍然是 CP——分区时少数派不可用</li></ul><p><strong>只有 Google 这种基建公司玩得起</strong>。</p><h3 id="_7-2-tidb-cockroachdb-怎么-穷人版-做到" tabindex="-1">7.2 TiDB / CockroachDB 怎么&quot;穷人版&quot;做到 <a class="header-anchor" href="#_7-2-tidb-cockroachdb-怎么-穷人版-做到" aria-label="Permalink to &quot;7.2 TiDB / CockroachDB 怎么&quot;穷人版&quot;做到&quot;">​</a></h3><p><strong>没有原子钟,用 HLC + 中心化 TSO(Timestamp Oracle)代替 TrueTime</strong>:</p><ul><li>TiDB:PD 集群单点发号(逻辑上集中,实际 Raft 高可用)</li><li>CockroachDB:HLC + uncertainty window,自动回滚冲突事务</li></ul><p>事务模型:<strong>Percolator(23 篇)</strong>——快照隔离 + 主键锁。</p><p>代价:</p><ul><li>每个事务跨网络至少 2 个 RTT(取 TS + commit)</li><li>TSO 单点瓶颈(虽然有缓解)</li><li>大事务慢</li></ul><blockquote><p><strong>TiDB / CockroachDB 是&quot;准 ACID&quot;——单数据中心强一致,跨地域降级</strong>。Spanner 是&quot;全球 ACID 但有 commit-wait&quot;。这两个挡掉了 99% 的工业需求,<strong>但代价仍然是单机 ACID 的几十倍延迟</strong>。</p></blockquote><hr><h2 id="八、mysql-主从-分布式-acid-一个常见的幻觉" tabindex="-1">八、MySQL 主从 ≠ 分布式 ACID:一个常见的幻觉 <a class="header-anchor" href="#八、mysql-主从-分布式-acid-一个常见的幻觉" aria-label="Permalink to &quot;八、MySQL 主从 ≠ 分布式 ACID:一个常见的幻觉&quot;">​</a></h2><p><strong>初级工程师最大的误区</strong>:以为&quot;我的 MySQL 是主从 + 半同步,所以是分布式 ACID&quot;。</p><p><strong>不是</strong>。让我们逐条破:</p><h3 id="_8-1-a-的幻觉" tabindex="-1">8.1 A 的幻觉 <a class="header-anchor" href="#_8-1-a-的幻觉" aria-label="Permalink to &quot;8.1 A 的幻觉&quot;">​</a></h3><p>跨库事务?<strong>XA</strong>(MySQL 内置)——21 篇会讲,是标准 2PC,<strong>生产几乎没人用</strong>(性能差、容易卡死)。<strong>大多数 MySQL 主从根本不做跨库事务</strong>——A 是单库 A,跨库 A 靠应用层补偿。</p><h3 id="_8-2-c-的幻觉" tabindex="-1">8.2 C 的幻觉 <a class="header-anchor" href="#_8-2-c-的幻觉" aria-label="Permalink to &quot;8.2 C 的幻觉&quot;">​</a></h3><p>跨库唯一约束?<strong>做不到</strong>——分库的 UNIQUE 只保证本分片唯一。<strong>全局唯一靠 Redis SETNX 或专门发号器</strong>。</p><h3 id="_8-3-i-的幻觉" tabindex="-1">8.3 I 的幻觉 <a class="header-anchor" href="#_8-3-i-的幻觉" aria-label="Permalink to &quot;8.3 I 的幻觉&quot;">​</a></h3><p>从库读到的数据<strong>滞后</strong>——即使你在主库 commit 了,从库可能还没拿到 binlog。<strong>从库读 + 主库写 = 已经破坏了线性一致</strong>。</p><h3 id="_8-4-d-的幻觉" tabindex="-1">8.4 D 的幻觉 <a class="header-anchor" href="#_8-4-d-的幻觉" aria-label="Permalink to &quot;8.4 D 的幻觉&quot;">​</a></h3><p>半同步只保证 binlog <strong>传到</strong> 至少一个从库,<strong>不等从库 fsync</strong>。从库收到但没 fsync 时挂了 → 数据丢。</p><p><strong>真正的多数派持久,要么 Loseless 半同步(MySQL 5.7+),要么 Group Replication / InnoDB Cluster</strong>。</p><blockquote><p>这是为什么互联网公司不真的把 MySQL 主从当强一致用——<strong>主从只解决&quot;读扩容 + 一定的高可用&quot;,不解决&quot;ACID&quot;</strong>。强 ACID 需求要么单库吃,要么上 NewSQL,要么应用层 Saga。</p></blockquote><hr><h2 id="九、工程选型-什么场景该怎么选" tabindex="-1">九、工程选型:什么场景该怎么选 <a class="header-anchor" href="#九、工程选型-什么场景该怎么选" aria-label="Permalink to &quot;九、工程选型:什么场景该怎么选&quot;">​</a></h2><p><strong>按业务场景给出选型矩阵</strong>:</p><table tabindex="0"><thead><tr><th>场景</th><th>强 A 需求</th><th>跨库否</th><th>推荐</th></tr></thead><tbody><tr><td>余额 / 账户 / 计费</td><td>高</td><td>否(单库)</td><td>MySQL / PG 单库事务</td></tr><tr><td>余额 + 跨地域</td><td>高</td><td>是</td><td>Spanner / OceanBase / TiDB</td></tr><tr><td>订单 + 库存(跨服务)</td><td>中</td><td>是</td><td>TCC(预占 + 确认)</td></tr><tr><td>订单流程(创建 → 支付 → 发货)</td><td>中</td><td>是</td><td>Saga</td></tr><tr><td>用户注册(跨用户中心 + 积分)</td><td>中</td><td>是</td><td>消息事务表 + 异步补偿</td></tr><tr><td>点赞 / 关注</td><td>低</td><td>是</td><td>CRDT / 最终一致</td></tr><tr><td>数据同步到 ES / 缓存</td><td>极低</td><td>是</td><td>binlog 监听 + 异步</td></tr></tbody></table><p><strong>判断口诀</strong>:</p><ol><li><strong>数据 &quot;错一笔会上新闻&quot; 吗?</strong> → 强 ACID,上 NewSQL 或单库</li><li><strong>数据 &quot;中间不一致几秒能接受&quot; 吗?</strong> → BASE,Saga / 消息</li><li><strong>数据 &quot;并发更新天然可合并&quot; 吗?</strong> → CRDT</li><li><strong>数据 &quot;几乎不并发&quot; 吗?</strong> → 单库够了,别复杂化</li></ol><h3 id="_9-1-ddd-视角-聚合根-一致性边界" tabindex="-1">9.1 DDD 视角:聚合根 = 一致性边界 <a class="header-anchor" href="#_9-1-ddd-视角-聚合根-一致性边界" aria-label="Permalink to &quot;9.1 DDD 视角:聚合根 = 一致性边界&quot;">​</a></h3><p>DDD 的&quot;聚合根&quot;是给分布式事务的<strong>最大馈赠</strong>——它定义了&quot;哪个范围内强一致,哪个范围外最终一致&quot;。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>聚合内(单数据库):ACID</span></span>
<span class="line"><span>聚合间(跨服务、跨库):最终一致 + Saga / 事件</span></span>
<span class="line"><span></span></span>
<span class="line"><span>如:</span></span>
<span class="line"><span>- 订单聚合(订单 + 订单项):一个事务</span></span>
<span class="line"><span>- 库存聚合(库存项):独立事务</span></span>
<span class="line"><span>- 跨这两个:Saga / TCC / 消息</span></span></code></pre></div><blockquote><p><strong>不分清&quot;哪些数据要在一个事务里&quot;,一上来就 2PC 全跨,系统必然慢且脆</strong>。<strong>先用 DDD 把一致性边界画好,然后边界内 ACID,边界外最终一致</strong>——这是工程上最实用的方法论。</p></blockquote><hr><h2 id="十、踩坑提醒" tabindex="-1">十、踩坑提醒 <a class="header-anchor" href="#十、踩坑提醒" aria-label="Permalink to &quot;十、踩坑提醒&quot;">​</a></h2><ol><li><strong>以为 MySQL 主从 = 分布式 ACID</strong>——主从只解决读扩容 + HA,<strong>跨库事务靠 XA(几乎没人用)或应用补偿</strong></li><li><strong>混淆 ACID 的 C 和 CAP 的 C</strong>——一个是业务约束,一个是多副本读写一致,<strong>完全不同</strong></li><li><strong>跨服务事务上 2PC</strong>——99% 场景该用 Saga / TCC,<strong>2PC 性能差且脆</strong></li><li><strong>以为半同步 = 强 D</strong>——半同步只保 binlog 到达,<strong>不等从库 fsync</strong>,要用 Loseless 模式</li><li><strong>强一致全部走 SERIALIZABLE</strong>——大多数业务 SI(快照隔离)就够了,<strong>真要 Serializable 性能踩烂</strong></li><li><strong>没有对账兜底</strong>——最终一致系统<strong>必须有对账作业</strong>,<strong>任何&quot;事件驱动&quot;系统不对账都是定时炸弹</strong></li><li><strong>业务约束写到应用层不写数据库</strong>——能在数据库做的 UNIQUE / FK / CHECK 一定在数据库做,<strong>应用层守门必有漏</strong></li><li><strong>跨聚合事务不写补偿</strong>——Saga 的核心就是补偿,<strong>没补偿就是裸事务,出错只能人工救火</strong></li><li><strong>忽略幂等</strong>——补偿事务 / 重试都要幂等,<strong>靠业务唯一键 + 状态机</strong></li><li><strong>以为 NewSQL 等于 ACID 免费</strong>——TiDB / CockroachDB 跨节点事务比单库慢 5-10 倍,<strong>热点行高并发仍然踩坑</strong>(用乐观锁需要处理大量重试)</li></ol><hr><h2 id="收束" tabindex="-1">收束 <a class="header-anchor" href="#收束" aria-label="Permalink to &quot;收束&quot;">​</a></h2><p>ACID 是单机时代的胜利,<strong>它把&quot;原子操作&quot;从硬件抬到了应用</strong>——开发者不必关心物理介质和并发原语,只要 BEGIN / COMMIT。</p><p>分布式让这个胜利破了功。<strong>A 破,C 破,I 破,D 破——每个字母都要重新发明一遍</strong>:</p><ul><li>A 的重发明 → 2PC / 3PC(21 篇) / Saga / TCC(22 篇)</li><li>C 的重发明 → 全局唯一服务 + DDD 聚合边界</li><li>I 的重发明 → SI / SSI / Percolator(23 篇)</li><li>D 的重发明 → 多数派持久 → Paxos / Raft(11-13 篇)</li></ul><p><strong>集大成是 Spanner</strong>(24 篇)——用 TrueTime 和 Paxos 硬把 ACID 拼回来。但 Spanner 之外的世界,大家都在和 ACID 妥协,<strong>选哪个字母让一步、让多少、用什么补</strong>,<strong>这就是分布式事务工程的全部艺术</strong>。</p><hr><p>下一篇:<code>21-2PC 与 3PC.md</code>,<strong>进入第五层的核心</strong>——两阶段提交是所有分布式事务的鼻祖,<strong>理解它的两个致命问题(同步阻塞 + 协调者单点),才能理解后续 Saga / TCC / Percolator / Spanner 在补什么洞</strong>。<strong>时序图务必看明白,2PC 的失败场景比成功场景重要十倍</strong>。</p>`,147)])])}const u=s(e,[["render",i]]);export{h as __pageData,u as default};
